import React, { useState } from "react";
import moment from "moment";
import { useProjectsContext } from "../hooks/useProjectsContext";
import { useAuthContext } from "../hooks/useAuthContext";
import { currencyFormatter } from "../utilities/currencyFormatter";
import ProjectForm from "./ProjectForm";

const ProjectDetails = ({ project }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isOverlayOpen, setIsOverlayOpen] = useState(false);

  const { dispatch } = useProjectsContext();
  const { user } = useAuthContext();

  const handleDelete = async () => {
    if (!user) {
      return;
    }

    const res = await fetch(
      `${process.env.REACT_APP_BASE_URL}/api/projects/${project._id}`,
      {
        method: "DELETE",
        headers: {
          Authorization: `Bearer ${user.token}`,
        },
      }
    );

    const json = await res.json();

    if (res.ok) {
      dispatch({ type: "DELETE_PROJECT", payload: json });
    }
  };

  const handleUpdate = () => {
    setIsModalOpen(true);
    setIsOverlayOpen(true);
  };

  const handleOverlay = () => {
    setIsModalOpen(false);
    setIsOverlayOpen(false);
  };

  return (
    <div className="project bg-white p-5 rounded-xl shadow-sm flex flex-col gap-5 w-[30rem]">
      <div className="project-top">
        <span className="text-indigo-600 text-sm">{project._id}</span>
        <h3 className="text-2xl font-semibold text-gray-900 mt-1">{project.title}</h3>
        <span className="uppercase text-xs tracking-widest text-gray-500 font-medium mt-1">
          {project.tech}
        </span>
      </div>

      <div className="project-mid text-gray-600 flex gap-10">
        <div className="left flex flex-col space-y-2">
          <span>Budget: {currencyFormatter(project.budget)}</span>
          <span>Added: {moment(project.createdAt).format("MMM DD, hh:mm A")}</span>
          <span>Updated: {moment(project.updatedAt).format("MMM DD, hh:mm A")}</span>
        </div>
        <div className="right flex flex-col space-y-2">
          <span>Manager: {project.manager}</span>
          <span>Developer: {project.dev}</span>
          <span>Duration: {`${project.duration} week${project.duration === 1 ? "" : "s"}`}</span>
        </div>
      </div>

      <div className="project-bottom flex gap-5">
        <button
          onClick={handleUpdate}
          className="bg-indigo-600 text-white py-2 px-5 rounded-md shadow-sm hover:bg-indigo-700 transition duration-150"
        >
          Update
        </button>
        <button
          onClick={handleDelete}
          className="text-red-600 hover:text-red-700 font-medium"
        >
          Delete
        </button>
      </div>

      {/* Modal */}
      <div
        className={`update-modal w-[35rem] fixed top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-white p-10 rounded-lg shadow-xl z-[2] ${
          isModalOpen ? "" : "hidden"
        }`}
      >
        <h2 className="text-2xl font-semibold text-gray-900 mb-6">
          Update Project
        </h2>

        <ProjectForm
          project={project}
          setIsModalOpen={setIsModalOpen}
          setIsOverlayOpen={setIsOverlayOpen}
        />
      </div>
    </div>
  );
};

export default React.memo(ProjectDetails);
